    ? (parseFloat(amount) * tokenPrice).toFixed(2)
    : undefined

  batchTokens.push({ 
    symbol: tokenSymbol, 
    amount, 
    logo: tokenLogo, 
    address: tokenAddr,
    usdValue
  })
  console.log('Added batch token with USD:', { symbol: tokenSymbol, amount, usdValue })
}

